using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        Dictionary<string, int> ages = new Dictionary<string, int>();
        ages["Ali"] = 25;
        ages["Veli"] = 30;
        ages["Ayse"] = 28;

        Console.WriteLine("Tum kayitlar:");
        foreach (KeyValuePair<string, int> entry in ages)
        {
            Console.WriteLine(entry.Key + " -> " + entry.Value + " yasinda");
        }

        // Anahtar kontrolu
        if (ages.ContainsKey("Ali"))
        {
            Console.WriteLine("\nAli'nin yasi: " + ages["Ali"]);
        }

        // Guncelleme
        ages["Ali"] = 26;
        Console.WriteLine("Ali'nin yeni yasi: " + ages["Ali"]);

        // Silme
        ages.Remove("Veli");
        Console.WriteLine("\nVeli silindikten sonra kayit sayisi: " + ages.Count);

        // TryGetValue
        if (ages.TryGetValue("Ayse", out int ayseAge))
        {
            Console.WriteLine("Ayse'nin yasi: " + ayseAge);
        }
    }
}
